class Solution:
    def checkArray(self, nums: List[int], k: int) -> bool:
        n = len(nums)
        diff = [0] * (n + 1)
        for i in range(n):
            # Apply the effect of previous operations
            nums[i] -= diff[i]
            if nums[i] < 0:
                return False
            if nums[i] > 0:
                # Apply operation on subarray starting at i
                if i + k > n:
                    return False
                nums[i + k] += nums[i]
                diff[i] += nums[i]
                diff[i + k] -= nums[i]
        return True
